with open('src/animations.tsx', 'r', encoding='utf-8') as f:
    c = f.read()
new = "import { useEffect } from 'react';\nimport { gsap } from 'gsap';\nimport { ScrollTrigger } from 'gsap/ScrollTrigger';\nexport default function AnimInit() {\n  useEffect(() => {\n    gsap.registerPlugin(ScrollTrigger);\n    gsap.from('.hero-title', {y:80,opacity:0,duration:1.2,ease:'expo.out',delay:0.15});\n    gsap.from('.hero-subtitle', {y:40,opacity:0,duration:1,ease:'expo.out',delay:0.4});\n    gsap.from('.hero-cta', {y:30,opacity:0,duration:0.8,ease:'power3.out',delay:0.7,scale:0.95});\n    gsap.from('.float-in', {y:60,opacity:0,duration:0.9,stagger:0.08,ease:'back.out(1.2)',scrollTrigger:{trigger:'.float-in',start:'top 85%'}});\n    gsap.from('.scale-in', {scale:0.96,opacity:0,duration:0.7,ease:'power2.out',scrollTrigger:{trigger:'.scale-in',start:'top 85%'}});\n    gsap.from('.section-title', {y:20,opacity:0,duration:0.6,ease:'power2.out',scrollTrigger:{trigger:'.section-title',start:'top 90%'}});\n    gsap.set('.card-item', {opacity:0,y:30});\n    gsap.to('.card-item', {opacity:1,y:0,stagger:0.08,duration:0.7,ease:'power3.out',scrollTrigger:{trigger:'.card-grid',start:'top 85%'}});\n    gsap.set('.stagger-item', {opacity:0,y:20});\n    gsap.to('.stagger-item', {opacity:1,y:0,stagger:0.06,duration:0.5,ease:'power2.out',scrollTrigger:{trigger:'.stagger-grid',start:'top 85%'}});\n    gsap.from('.fade-up', {y:20,opacity:0,duration:0.5,stagger:0.04,ease:'power2.out',scrollTrigger:{trigger:'.fade-up',start:'top 85%'}});\n    gsap.from('.hero-image', {scale:1.05,opacity:0,duration:1.5,ease:'power1.out',scrollTrigger:{trigger:'.hero-image',start:'top 60%',end:'bottom top',scrub:1}});\n    gsap.from('.parallax-up', {y:80,opacity:0,duration:0.8,ease:'power2.out',scrollTrigger:{trigger:'.parallax-up',start:'top 85%',end:'bottom 60%',scrub:1}});\n    gsap.to('.parallax-slow', {y:-40,ease:'none',scrollTrigger:{trigger:'.parallax-slow',start:'top bottom',end:'bottom top',scrub:1.5}});\n    gsap.from('.stagger-cards', {y:30,opacity:0,stagger:0.05,duration:0.65,ease:'back.out(1.2)',scrollTrigger:{trigger:'.stagger-cards',start:'top 85%'}});\n    gsap.from('.hero-link-large', {y:10,opacity:0,duration:0.6,ease:'power2.out',delay:0.9});\n    setTimeout(() => ScrollTrigger.refresh(), 200);\n  }, []);\n  return null;\n}"
with open('src/animations.tsx', 'w', encoding='utf-8') as f:
    f.write(new)
